scripts.build:
vite build && node -e "const fs=require('fs');fs.writeFileSync('dist-electron/preload.mjs', 'import { contextBridge, ipcRenderer } from "electron";

contextBridge.exposeInMainWorld("traceAPI", {
  generate(job) { return ipcRenderer.invoke("trace:generate", job); },
  getAIStatus() { return ipcRenderer.invoke("trace:get-ai-status"); },
  startAI() { return ipcRenderer.invoke("trace:start-ai"); },
  onAIStatus(callback) { const listener = (_event, status) => callback(status); ipcRenderer.on("trace:ai-status", listener); return () => ipcRenderer.off("trace:ai-status", listener); }
});
')"
